import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { Order } from '../../core/models';

/**
 * Storefront order history (`orders`, authGuard). Caller's orders newest-first.
 * service_agent wires ApiService.myOrders() in ngOnInit().
 */
@Component({
  selector: 'app-orders',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './orders.component.html',
  styleUrl: './orders.component.css',
})
export class OrdersComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  // Mock order history — service_agent replaces with ApiService.myOrders().
  readonly orders = signal<Order[]>([
    {
      id: 'o1002',
      userId: 'demo-shopper',
      status: 'placed',
      shipName: 'Ada Lovelace',
      shipAddress: '123 Analytical Engine Way, London',
      totalCents: 25300,
      createdAt: '2026-07-11T14:20:00.000Z',
      items: [
        { id: 'oi1', orderId: 'o1002', productId: 'p1', qty: 1, unitPriceCents: 18900,
          product: { id: 'p1', name: 'Aurora Wireless Headphones', description: '', priceCents: 18900, imageUrl: '', stockQty: 24 } },
        { id: 'oi2', orderId: 'o1002', productId: 'p2', qty: 2, unitPriceCents: 3200,
          product: { id: 'p2', name: 'Terra Insulated Bottle', description: '', priceCents: 3200, imageUrl: '', stockQty: 120 } },
      ],
    },
    {
      id: 'o1001',
      userId: 'demo-shopper',
      status: 'shipped',
      shipName: 'Ada Lovelace',
      shipAddress: '123 Analytical Engine Way, London',
      totalCents: 6400,
      createdAt: '2026-07-04T09:05:00.000Z',
      items: [
        { id: 'oi3', orderId: 'o1001', productId: 'p4', qty: 1, unitPriceCents: 6400,
          product: { id: 'p4', name: 'Lumen Desk Lamp', description: '', priceCents: 6400, imageUrl: '', stockQty: 3 } },
      ],
    },
  ]);

  constructor(private api: ApiService) {}

  ngOnInit(): void {
    this.loading.set(true);
    this.error.set(null);
    this.api.myOrders().subscribe({
      next: (orders) => {
        this.orders.set(orders);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load your orders.');
        this.loading.set(false);
      },
    });
  }

  itemCount(order: Order): number {
    return order.items.reduce((sum, i) => sum + i.qty, 0);
  }

  money(cents: number): string {
    return '$' + (cents / 100).toFixed(2);
  }
}
